function solve(digitSum: number[]): number {
    // Helper function to calculate sum of digits
    const sumOfDigits = (n: number): number => {
        let sum = 0;
        let s = Math.abs(n);
        while (s > 0) {
            sum += s % 10;
            s = Math.floor(s / 10);
        }
        return sum;
    };

    // Step 1: Pre-calculate PossibleNumbers[S]
    // PossibleNumbers[S] stores a sorted list of numbers x in [0, 5000] with sum of digits S.
    const MAX_DIGIT_SUM = 50;
    const possibleNumbers: number[][] = Array(MAX_DIGIT_SUM + 1).fill(0).map(() => []);

    for (let x = 0; x <= 5000; x++) {
        const s = sumOfDigits(x);
        if (s <= MAX_DIGIT_SUM) {
            possibleNumbers[s].push(x);
        }
    }

    // Sort them just in case (though the loop generates them in order)
    for (let s = 0; s <= MAX_DIGIT_SUM; s++) {
        possibleNumbers[s].sort((a, b) => a - b);
    }

    const N = digitSum.length;

    // DP initialization: DP_prev stores {value: count} for the previous step i-1.
    // For i=0, DP_prev will effectively store results for i=0.
    let dpPrev: Map<number, number> | null = null;

    for (let i = 0; i < N; i++) {
        const currentSum = digitSum[i];
        const V_i = possibleNumbers[currentSum];

        if (V_i.length === 0) {
            return 0; // No number exists for this digit sum in range [0, 5000]
        }

        const dpCurr: Map<number, number> = new Map();

        if (i === 0) {
            // Base case: i=0. Every valid number contributes 1 way.
            for (const v of V_i) {
                dpCurr.set(v, 1);
            }
        } else {
            // Transition step i > 0

            // 1. Prepare U (V_{i-1} values) and counts from dpPrev
            // U is sorted list of previous values u
            const U = Array.from(dpPrev.keys()).sort((a, b) => a - b);

            // 2. Calculate prefix sums P based on U
            const P: number[] = new Array(U.length).fill(0);
            let currentSumCount = 0;
            for (let j = 0; j < U.length; j++) {
                const u = U[j];
                currentSumCount = (currentSumCount + dpPrev.get(u)!);
                P[j] = currentSumCount % MOD;
            }

            // 3. Iterate over V_i (current values v) and calculate DP[i][v]
            for (const v of V_i) {
                // Find the largest index j such that U[j] <= v.
                // Binary search (find insertion point for v+1, then step back one)

                let low = 0;
                let high = U.length - 1;
                let bestIndex = -1;

                while (low <= high) {
                    const mid = Math.floor((low + high) / 2);
                    if (U[mid] <= v) {
                        bestIndex = mid;
                        low = mid + 1; // Try to find a larger matching index
                    } else {
                        high = mid - 1; // U[mid] is too large
                    }
                }

                let count = 0;
                if (bestIndex !== -1) {
                    count = P[bestIndex];
                }

                dpCurr.set(v, count);
            }
        }

        dpPrev = dpCurr;
    }

    // Final result: Sum all counts in the last DP state
    let totalCount = 0;
    if (dpPrev) {
        for (const count of dpPrev.values()) {
            totalCount = (totalCount + count) % MOD;
        }
    }

    return totalCount;
