    for (let v = 0; v <= MAX_VAL; v++) {
        if (digitSumsMap[v] === d0) {
            dp_prev[v] = 1;
        }
    }

    // Iteration: i = 1 to N-1
    const N = digitSum.length;
    for (let i = 1; i < N; i++) {
        const d_i = digitSum[i];
        let dp_curr = new Array(SIZE).fill(0);

        // Calculate Prefix Sums of dp_prev
        // prefixSum[k] = sum(dp_prev[j] for j=0 to k)
        let prefixSumPrev = new Array(SIZE).fill(0);
        let currentSum = 0;
        for (let k = 0; k <= MAX_VAL; k++) {
            currentSum = (currentSum + dp_prev[k]) % MOD;
            prefixSumPrev[k] = currentSum;
        }

        // Calculate dp_curr[v]
        for (let v = 0; v <= MAX_VAL; v++) {
            if (digitSumsMap[v] === d_i) {
                // dp_curr[v] = sum(dp_prev[u] for u <= v)
                // This is exactly prefixSumPrev[v]
                dp_curr[v] = prefixSumPrev[v];
            }
        }

        // Move current results to previous for next iteration
        dp_prev = dp_curr;
    }

    // Final Result: Sum up all values in the last DP array
    let totalCount = 0;
    for (let v = 0; v <= MAX_VAL; v++) {
        totalCount = (totalCount + dp_prev[v]) % MOD;
    }

    return totalCount;
}
